#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> rotateArray(vector<int>& nums, int k) {
        k = k % nums.size();
        vector<int> ans(nums.begin() + k, nums.end());
        ans.insert(ans.end(), nums.begin(), nums.begin() + k);
        return ans;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    vector<int> ans = sol.rotateArray(nums, k);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
